import requests
import json

KONG_ADMIN_URL = "http://localhost:8001"

def create_service(name, url):
    service_data = {
        "name": name,
        "url": url
    }
    response = requests.post(f"{KONG_ADMIN_URL}/services", json=service_data)
    return response.json()

def create_route(service_id, paths, hosts=None):
    route_data = {
        "service": {"id": service_id},
        "paths": paths
    }
    if hosts:
        route_data["hosts"] = hosts
    response = requests.post(f"{KONG_ADMIN_URL}/routes", json=route_data)
    return response.json()

def create_upstream(name, algorithm="round-robin"):
    upstream_data = {
        "name": name,
        "algorithm": algorithm
    }
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams", json=upstream_data)
    return response.json()

def create_target(upstream_id, target, port=8000):
    target_data = {
        "upstream": {"id": upstream_id},
        "target": target,
        "port": port
    }
    response = requests.post(f"{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets", json=target_data)
    return response.json()

def main():
    # Create a service
    service = create_service("my-service", "http://mockbin.org")
    service_id = service["id"]
    
    # Create a route for the service
    route = create_route(service_id, ["/my-service"])
    
    # Create an upstream
    upstream = create_upstream("my-upstream")
    upstream_id = upstream["id"]
    
    # Create targets for the upstream
    create_target(upstream_id, "127.0.0.1", 8000)
    create_target(upstream_id, "127.0.0.1", 8001)

if __name__ == "__main__":
    main()